import{_ as i,o as a,c as n,ae as e}from"./chunks/framework.CB71nIlf.js";const c=JSON.parse('{"title":"社交分享","description":"","frontmatter":{},"headers":[],"relativePath":"2-experimenter-manual/5-invite-system/5-3-social-share.md","filePath":"2-experimenter-manual/5-invite-system/5-3-social-share.md"}'),t={name:"2-experimenter-manual/5-invite-system/5-3-social-share.md"};function r(o,l,s,h,u,p){return a(),n("div",null,[...l[0]||(l[0]=[e(`<h1 id="社交分享" tabindex="-1">社交分享 <a class="header-anchor" href="#社交分享" aria-label="Permalink to &quot;社交分享&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>社交分享功能允许您将邀请链接快速分享到社交媒体平台，扩大邀请的覆盖面。通过社交媒体分享，您可以触达更广泛的潜在被试群体，提高邀请的传播效率。</p><h2 id="进入社交分享" tabindex="-1">进入社交分享 <a class="header-anchor" href="#进入社交分享" aria-label="Permalink to &quot;进入社交分享&quot;">​</a></h2><p>登录后，进入&quot;邀请用户&quot;页面，在页面左侧&quot;分享邀请链接&quot;区域找到社交媒体分享按钮。</p><h2 id="功能说明" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明" aria-label="Permalink to &quot;功能说明&quot;">​</a></h2><h3 id="_1-支持的社交平台" tabindex="-1">1. 支持的社交平台 <a class="header-anchor" href="#_1-支持的社交平台" aria-label="Permalink to &quot;1. 支持的社交平台&quot;">​</a></h3><h4 id="_1-1-twitter" tabindex="-1">1.1 Twitter <a class="header-anchor" href="#_1-1-twitter" aria-label="Permalink to &quot;1.1 Twitter&quot;">​</a></h4><p><strong>平台特点</strong>：</p><ul><li>全球性社交媒体平台</li><li>适合学术和专业交流</li><li>支持话题标签传播</li></ul><p><strong>分享方式</strong>：</p><ol><li>点击Twitter分享按钮（蓝色按钮）</li><li>自动打开Twitter分享对话框</li><li>预填分享文本：&quot;加入我们的认知科学研究平台！{邀请链接}&quot;</li><li>可以编辑分享文本</li><li>点击&quot;Tweet&quot;发布</li></ol><p><strong>使用建议</strong>：</p><ul><li>添加相关话题标签（如#心理学研究 #认知科学）</li><li>简要说明实验内容</li><li>@相关的学术账号或机构</li></ul><h4 id="_1-2-linkedin" tabindex="-1">1.2 LinkedIn <a class="header-anchor" href="#_1-2-linkedin" aria-label="Permalink to &quot;1.2 LinkedIn&quot;">​</a></h4><p><strong>平台特点</strong>：</p><ul><li>专业社交网络平台</li><li>适合学术和职业交流</li><li>用户群体专业性强</li></ul><p><strong>分享方式</strong>：</p><ol><li>点击LinkedIn分享按钮（蓝色按钮）</li><li>自动打开LinkedIn分享对话框</li><li>自动填充邀请链接</li><li>可以添加分享说明</li><li>点击&quot;Post&quot;发布</li></ol><p><strong>使用建议</strong>：</p><ul><li>说明研究的专业价值</li><li>强调参与的学术意义</li><li>针对专业人士撰写内容</li></ul><h3 id="_2-分享操作" tabindex="-1">2. 分享操作 <a class="header-anchor" href="#_2-分享操作" aria-label="Permalink to &quot;2. 分享操作&quot;">​</a></h3><h4 id="_2-1-点击分享按钮" tabindex="-1">2.1 点击分享按钮 <a class="header-anchor" href="#_2-1-点击分享按钮" aria-label="Permalink to &quot;2.1 点击分享按钮&quot;">​</a></h4><p><strong>操作步骤</strong>：</p><ol><li>在邀请页面找到社交分享按钮</li><li>选择要分享的平台（Twitter或LinkedIn）</li><li>点击对应的分享按钮</li><li>在弹出的窗口中完成分享</li></ol><p><strong>窗口特点</strong>：</p><ul><li>在新窗口打开（600x400像素）</li><li>使用各平台的官方分享API</li><li>自动填充邀请链接</li><li>支持编辑分享内容</li></ul><h4 id="_2-2-编辑分享内容" tabindex="-1">2.2 编辑分享内容 <a class="header-anchor" href="#_2-2-编辑分享内容" aria-label="Permalink to &quot;2.2 编辑分享内容&quot;">​</a></h4><p><strong>可编辑内容</strong>：</p><ul><li>分享文本</li><li>话题标签</li><li>@提及的用户</li><li>附加说明</li></ul><p><strong>编辑建议</strong>：</p><ul><li>保留邀请链接</li><li>添加吸引人的描述</li><li>使用相关的话题标签</li><li>保持内容简洁明了</li></ul><h4 id="_2-3-完成分享" tabindex="-1">2.3 完成分享 <a class="header-anchor" href="#_2-3-完成分享" aria-label="Permalink to &quot;2.3 完成分享&quot;">​</a></h4><p><strong>发布后</strong>：</p><ul><li>关闭分享窗口</li><li>返回邀请页面</li><li>分享内容出现在您的社交媒体账号上</li><li>您的关注者可以看到邀请链接</li></ul><h3 id="_3-分享内容优化" tabindex="-1">3. 分享内容优化 <a class="header-anchor" href="#_3-分享内容优化" aria-label="Permalink to &quot;3. 分享内容优化&quot;">​</a></h3><h4 id="_3-1-文案建议" tabindex="-1">3.1 文案建议 <a class="header-anchor" href="#_3-1-文案建议" aria-label="Permalink to &quot;3.1 文案建议&quot;">​</a></h4><p><strong>吸引注意</strong>：</p><ul><li>使用简洁有力的开头</li><li>突出实验的独特性</li><li>强调参与的价值</li></ul><p><strong>示例文案</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🧠 诚邀参与认知科学研究！</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我们正在进行一项关于工作记忆的在线实验，</span></span>
<span class="line"><span>只需20分钟，即可了解您的认知特点。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>参与即可获得：</span></span>
<span class="line"><span>✅ 个性化认知报告</span></span>
<span class="line"><span>✅ 为科学研究贡献力量</span></span>
<span class="line"><span>✅ 平台积分奖励</span></span>
<span class="line"><span></span></span>
<span class="line"><span>点击链接注册参与：{邀请链接}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#心理学研究 #认知科学 #实验招募</span></span></code></pre></div><h4 id="_3-2-话题标签" tabindex="-1">3.2 话题标签 <a class="header-anchor" href="#_3-2-话题标签" aria-label="Permalink to &quot;3.2 话题标签&quot;">​</a></h4><p><strong>推荐标签</strong>：</p><ul><li>#心理学研究</li><li>#认知科学</li><li>#实验招募</li><li>#被试招募</li><li>#学术研究</li><li>#在线实验</li></ul><p><strong>使用技巧</strong>：</p><ul><li>选择相关且热门的标签</li><li>标签数量建议3-5个</li><li>避免使用过于宽泛的标签</li></ul><h4 id="_3-3-视觉元素" tabindex="-1">3.3 视觉元素 <a class="header-anchor" href="#_3-3-视觉元素" aria-label="Permalink to &quot;3.3 视觉元素&quot;">​</a></h4><p><strong>增强吸引力</strong>：</p><ul><li>使用表情符号（如🧠💡📊）</li><li>使用项目符号列表</li><li>突出关键信息</li><li>保持排版整洁</li></ul><h3 id="_4-分享效果追踪" tabindex="-1">4. 分享效果追踪 <a class="header-anchor" href="#_4-分享效果追踪" aria-label="Permalink to &quot;4. 分享效果追踪&quot;">​</a></h3><h4 id="_4-1-查看分享数据" tabindex="-1">4.1 查看分享数据 <a class="header-anchor" href="#_4-1-查看分享数据" aria-label="Permalink to &quot;4.1 查看分享数据&quot;">​</a></h4><p><strong>追踪方式</strong>：</p><ul><li>通过社交媒体平台的分析工具</li><li>查看帖子的浏览量、点赞数、转发数</li><li>分析哪些内容更受欢迎</li></ul><h4 id="_4-2-优化分享策略" tabindex="-1">4.2 优化分享策略 <a class="header-anchor" href="#_4-2-优化分享策略" aria-label="Permalink to &quot;4.2 优化分享策略&quot;">​</a></h4><p><strong>数据分析</strong>：</p><ul><li>记录不同文案的效果</li><li>分析最佳发布时间</li><li>了解目标受众的偏好</li><li>持续优化分享内容</li></ul><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><h3 id="_1-选择合适的平台" tabindex="-1">1. 选择合适的平台 <a class="header-anchor" href="#_1-选择合适的平台" aria-label="Permalink to &quot;1. 选择合适的平台&quot;">​</a></h3><p><strong>Twitter适合</strong>：</p><ul><li>快速传播信息</li><li>触达广泛受众</li><li>学术交流和讨论</li></ul><p><strong>LinkedIn适合</strong>：</p><ul><li>专业人士招募</li><li>学术合作推广</li><li>职业相关研究</li></ul><h3 id="_2-最佳发布时间" tabindex="-1">2. 最佳发布时间 <a class="header-anchor" href="#_2-最佳发布时间" aria-label="Permalink to &quot;2. 最佳发布时间&quot;">​</a></h3><p><strong>Twitter</strong>：</p><ul><li>工作日上午9-11点</li><li>下午1-3点</li><li>晚上7-9点</li></ul><p><strong>LinkedIn</strong>：</p><ul><li>工作日上午7-9点</li><li>中午12-1点</li><li>下午5-6点</li></ul><p><strong>注意事项</strong>：</p><ul><li>考虑目标受众的时区</li><li>避免在深夜或凌晨发布</li><li>周末发布效果可能较差</li></ul><h3 id="_3-提高分享效果" tabindex="-1">3. 提高分享效果 <a class="header-anchor" href="#_3-提高分享效果" aria-label="Permalink to &quot;3. 提高分享效果&quot;">​</a></h3><p><strong>内容质量</strong>：</p><ul><li>提供有价值的信息</li><li>使用专业的语言</li><li>保持真实和透明</li></ul><p><strong>互动参与</strong>：</p><ul><li>及时回复评论和私信</li><li>感谢转发和支持</li><li>解答潜在被试的疑问</li></ul><p><strong>持续推广</strong>：</p><ul><li>定期分享更新</li><li>分享实验进展</li><li>感谢参与者的贡献</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><p>⚠️ <strong>重要提示</strong>：</p><ol><li><p><strong>平台规则</strong></p><ul><li>遵守各社交平台的使用条款</li><li>不要发送垃圾信息</li><li>不要过度频繁发布</li></ul></li><li><p><strong>内容真实性</strong></p><ul><li>不要发布虚假信息</li><li>不要夸大实验效果</li><li>不要承诺无法兑现的奖励</li></ul></li><li><p><strong>隐私保护</strong></p><ul><li>不要泄露被试的个人信息</li><li>不要分享未经授权的数据</li><li>尊重参与者的隐私权</li></ul></li><li><p><strong>专业形象</strong></p><ul><li>保持专业的语言和态度</li><li>避免使用不当的表情或图片</li><li>维护学术研究的严肃性</li></ul></li><li><p><strong>版权问题</strong></p><ul><li>不要使用未经授权的图片或内容</li><li>注明引用来源</li><li>尊重知识产权</li></ul></li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q1-为什么分享窗口打不开" tabindex="-1">Q1: 为什么分享窗口打不开？ <a class="header-anchor" href="#q1-为什么分享窗口打不开" aria-label="Permalink to &quot;Q1: 为什么分享窗口打不开？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>检查浏览器是否阻止了弹出窗口</li><li>在浏览器设置中允许弹出窗口</li><li>尝试刷新页面后重试</li></ul><h3 id="q2-可以同时分享到多个平台吗" tabindex="-1">Q2: 可以同时分享到多个平台吗？ <a class="header-anchor" href="#q2-可以同时分享到多个平台吗" aria-label="Permalink to &quot;Q2: 可以同时分享到多个平台吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>可以，分别点击不同平台的分享按钮</li><li>每个平台需要单独操作</li><li>建议根据平台特点调整分享内容</li></ul><h3 id="q3-分享后可以删除吗" tabindex="-1">Q3: 分享后可以删除吗？ <a class="header-anchor" href="#q3-分享后可以删除吗" aria-label="Permalink to &quot;Q3: 分享后可以删除吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>可以，在对应的社交媒体平台上删除帖子</li><li>删除后链接仍然有效</li><li>已经看到的用户仍可以访问链接</li></ul><h3 id="q4-分享内容可以自定义吗" tabindex="-1">Q4: 分享内容可以自定义吗？ <a class="header-anchor" href="#q4-分享内容可以自定义吗" aria-label="Permalink to &quot;Q4: 分享内容可以自定义吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>可以，在分享对话框中编辑内容</li><li>建议保留邀请链接</li><li>可以添加个性化的描述和标签</li></ul><h3 id="q5-如何知道有多少人通过社交分享注册" tabindex="-1">Q5: 如何知道有多少人通过社交分享注册？ <a class="header-anchor" href="#q5-如何知道有多少人通过社交分享注册" aria-label="Permalink to &quot;Q5: 如何知道有多少人通过社交分享注册？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>查看邀请统计中的&quot;成功注册&quot;数量</li><li>无法区分具体来源（邮件、社交媒体等）</li><li>建议使用不同的邀请码追踪不同渠道</li></ul><h3 id="q6-分享频率有限制吗" tabindex="-1">Q6: 分享频率有限制吗？ <a class="header-anchor" href="#q6-分享频率有限制吗" aria-label="Permalink to &quot;Q6: 分享频率有限制吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>平台本身没有限制</li><li>但社交媒体平台可能有发布频率限制</li><li>建议合理控制分享频率，避免被视为垃圾信息</li></ul><h3 id="q7-可以分享到微信或微博吗" tabindex="-1">Q7: 可以分享到微信或微博吗？ <a class="header-anchor" href="#q7-可以分享到微信或微博吗" aria-label="Permalink to &quot;Q7: 可以分享到微信或微博吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>当前版本不支持直接分享到微信或微博</li><li>可以复制邀请链接手动分享</li><li>未来可能会添加更多平台支持</li></ul><h3 id="q8-分享后没有人注册怎么办" tabindex="-1">Q8: 分享后没有人注册怎么办？ <a class="header-anchor" href="#q8-分享后没有人注册怎么办" aria-label="Permalink to &quot;Q8: 分享后没有人注册怎么办？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>优化分享内容，使其更吸引人</li><li>选择合适的发布时间</li><li>增加分享频率</li><li>尝试不同的社交平台</li><li>结合邮件邀请等其他方式</li></ul><h3 id="q9-可以在分享中添加图片吗" tabindex="-1">Q9: 可以在分享中添加图片吗？ <a class="header-anchor" href="#q9-可以在分享中添加图片吗" aria-label="Permalink to &quot;Q9: 可以在分享中添加图片吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>取决于社交平台的功能</li><li>Twitter和LinkedIn支持添加图片</li><li>在分享对话框中可以上传图片</li><li>建议使用与实验相关的专业图片</li></ul><h3 id="q10-社交分享和邮件邀请哪个效果更好" tabindex="-1">Q10: 社交分享和邮件邀请哪个效果更好？ <a class="header-anchor" href="#q10-社交分享和邮件邀请哪个效果更好" aria-label="Permalink to &quot;Q10: 社交分享和邮件邀请哪个效果更好？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>各有优势，建议结合使用</li><li>社交分享：覆盖面广，传播快</li><li>邮件邀请：针对性强，转化率高</li><li>根据目标受众选择合适的方式</li></ul><hr><p><strong>需要更多帮助？</strong> 请查看：</p><ul><li><a href="/cogniand-manual.github.io/2-experimenter-manual/5-invite-system/5-1-generate-invite.html">生成邀请链接</a></li><li><a href="/cogniand-manual.github.io/2-experimenter-manual/5-invite-system/5-2-send-email.html">邮件邀请</a></li><li><a href="/cogniand-manual.github.io/3-subject-manual/5-personal-center.html">个人中心</a></li><li><a href="/cogniand-manual.github.io/7-technical-support/1-contact.html">技术支持</a></li></ul>`,113)])])}const g=i(t,[["render",r]]);export{c as __pageData,g as default};
